// QTP Order Lifecycle Ingestor v1.0 (Conclave gap G22)
// Polls Alpaca paper /v2/orders?status=all and stages idempotent inserts into quantum.order_events.
// Credential pattern replicated from Trailing Stop Manager (vFnPjyx8srnzcYgV) 'Trail Stops' node.
const nowET = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
const dowET = nowET.getDay();
const hourET = nowET.getHours();
const inWindow = dowET >= 1 && dowET <= 5 && hourET >= 9 && hourET <= 16;
if ($execution.mode === 'production' && !inWindow) { return []; }
const sd = $getWorkflowStaticData('global');
const _creds = sd._credentials || {};
const ALPACA_KEY = $vars.ALPACA_API_KEY || $vars.ALPACA_KEY_ID || sd._alpaca_key || _creds.alpaca_key || '';
const ALPACA_SECRET = $vars.ALPACA_SECRET_KEY || $vars.ALPACA_SECRET || sd._alpaca_secret || _creds.alpaca_secret || '';
const BASE = $vars.ALPACA_BASE_URL || _creds.alpaca_base || 'https://paper-api.alpaca.markets';
if (!ALPACA_KEY || !ALPACA_SECRET) { throw new Error('OLI_NO_ALPACA_CREDS: seed n8n instance vars ALPACA_API_KEY + ALPACA_SECRET_KEY, or this workflow staticData _alpaca_key/_alpaca_secret (staticData does NOT transfer from Trailing Stop Manager).'); }
const HDR = { 'APCA-API-KEY-ID': ALPACA_KEY, 'APCA-API-SECRET-KEY': ALPACA_SECRET };
const orders = await this.helpers.httpRequest({ method: 'GET', url: BASE + '/v2/orders?status=all&limit=500&direction=desc&nested=true', headers: HDR, json: true });
if (!Array.isArray(orders)) { throw new Error('OLI_BAD_RESPONSE: expected array from /v2/orders, got ' + typeof orders); }
function esc(v) { return String(v).replace(/'/g, "''").replace(/\$(\d)/g, 'USD $1'); }
function txt(v) { if (v === null || v === undefined || v === '') { return 'NULL'; } return "'" + esc(v) + "'"; }
function num(v) { if (v === null || v === undefined || v === '') { return 'NULL::numeric'; } const n = Number(v); if (!isFinite(n)) { return 'NULL::numeric'; } return "'" + n + "'::numeric"; }
function toRow(o) {
  const ts = o.updated_at || o.submitted_at || o.created_at || '';
  if (!o.id || !ts) { return null; }
  const eventId = o.id + ':' + o.status + ':' + ts;
  let rp = JSON.stringify(o) || '{}';
  if (rp.length > 8000) { rp = JSON.stringify({ _truncated: true, id: o.id, status: o.status, symbol: o.symbol, order_type: o.type, updated_at: o.updated_at }); }
  const side = o.position_intent ? String(o.side || '') + ':' + o.position_intent : String(o.side || 'unknown');
  const vals = [
    txt(eventId), txt(o.id), txt(o.id), "'alpaca_paper'",
    txt(ts) + '::timestamptz', txt(String(ts).slice(0, 10)) + '::date',
    txt(o.symbol || 'UNKNOWN'), txt(side), txt(o.type), txt(o.time_in_force),
    txt(String(o.status || 'unknown').toUpperCase()),
    num(o.qty), num(o.filled_qty), num(o.limit_price), num(o.stop_price), num(o.filled_avg_price),
    txt(rp) + '::jsonb', txt(eventId), 'now()'
  ];
  return { eventId: eventId, sql: '(' + vals.join(', ') + ')' };
}
const rows = [];
const seen = {};
for (const o of orders) {
  const fam = [o].concat(Array.isArray(o.legs) ? o.legs : []);
  for (const ord of fam) {
    const r = toRow(ord);
    if (r && !seen[r.eventId]) { seen[r.eventId] = true; rows.push(r.sql); }
  }
}
if (rows.length === 0) { return []; }
const cols = 'order_event_id, order_id, broker_order_id, account_id, event_ts, event_date, symbol, side, order_type, time_in_force, order_status, requested_quantity, filled_quantity, limit_price, stop_price, avg_fill_price, raw_payload, idempotency_key, ingested_at';
const sql = 'INSERT INTO quantum.order_events (' + cols + ') SELECT * FROM (VALUES ' + rows.join(', ') + ') AS v(' + cols + ') WHERE NOT EXISTS (SELECT 1 FROM quantum.order_events oe WHERE oe.order_event_id = v.order_event_id)';
return [{ json: { __supabase_insert_sql: sql, fetched_orders: orders.length, candidate_rows: rows.length, base_used: BASE, window_et_ok: inWindow } }];
